const now = new Date();
const firstOfThisMonth = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), 1));
const firstOfPrevMonth = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth() - 1, 1));
const yyyymm = firstOfPrevMonth.toISOString().slice(0,7);
return [{ json: {
  correlationId: `monthly-${yyyymm}-${Math.floor(Math.random()*1e6)}`,
  yyyymm,
  rangeStart: firstOfPrevMonth.toISOString().slice(0,10),
  rangeEndExclusive: firstOfThisMonth.toISOString().slice(0,10)
}}];

const range = $node['Stamp range'].json;
const rows = $items().map(i => i.json).filter(r => {
  const t = (r.appliedAt || '').slice(0,10);
  return t >= range.rangeStart && t < range.rangeEndExclusive;
});
const headers = ['correlationId','op','provider','orderId','invoiceNumber','status','appliedAt'];
const lines = [headers.join(',')];
for (const r of rows) {
  lines.push(headers.map(h => JSON.stringify(r[h] ?? '')).join(','));
}
const counts = rows.reduce((acc,r) => { acc[r.op] = (acc[r.op]||0) + 1; return acc; }, {});
return [{ json: {
  correlationId: range.correlationId,
  yyyymm: range.yyyymm,
  csv: lines.join('\n'),
  rowCount: rows.length,
  counts
}}];

